{
  "name": "Talk-Back Book: Viscosity",
  "description": "An interactive engineering textbook chapter on Viscosity and Fluid Mechanics using Socratic AI coaching and real-time simulations.",
  "requestFramePermissions": []
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum Step {
  HOOK = 0,
  EXPLORATION = 1,
  THEORY = 2,
  CHALLENGE = 3,
  COMPLETION = 4
}

export interface FeedbackResponse {
  isCorrect: boolean;
  message: string;
  scaffoldingQuestion?: string;
}

export interface AttemptState {
  count: number;
  lastFeedback: string;
  isUnlocked: boolean;
}

import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

const SYSTEM_PROMPT = `You are an expert Fluid Mechanics educator and AI learning architect for a "Talk-Back Book." 
Your role is to act as a Socratic coach, misconception detector, and scaffolding provider.

RULES:
1. NEVER give the final answer directly unless it's the user's 3rd failed attempt.
2. Be conversational but rigorous.
3. Use the "Predict -> Observe -> Explain" model.
4. If a user is wrong, identify the misconception and ask a single, highly-focused scaffolding question to guide them.
5. Your response MUST be in JSON format.`;

export const analyzeResponse = async (
  topic: string,
  question: string,
  userAnswer: string,
  attemptNumber: number
): Promise<{ isCorrect: boolean; message: string; scaffoldingQuestion?: string }> => {
  const model = 'gemini-3-flash-preview';

  const prompt = `
    Topic: ${topic}
    Question: ${question}
    User's Answer: "${userAnswer}"
    Attempt Number: ${attemptNumber}

    Task:
    - Determine if the answer is conceptually correct.
    - If correct, congratulate them and briefly explain why.
    - If incorrect and attempt < 3, provide a hint (scaffolding question) that addresses their likely misconception.
    - If incorrect and attempt == 3, provide the correct explanation and answer.

    Return JSON format:
    {
      "isCorrect": boolean,
      "message": "Feedback for the user",
      "scaffoldingQuestion": "A follow-up hint question (optional if correct or 3rd attempt)"
    }
  `;

  try {
    const response = await ai.models.generateContent({
      model,
      contents: prompt,
      config: {
        systemInstruction: SYSTEM_PROMPT,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            isCorrect: { type: Type.BOOLEAN },
            message: { type: Type.STRING },
            scaffoldingQuestion: { type: Type.STRING }
          },
          required: ["isCorrect", "message"]
        }
      }
    });

    return JSON.parse(response.text || '{}');
  } catch (error) {
    console.error("Gemini API Error:", error);
    return {
      isCorrect: false,
      message: "I'm having trouble processing that right now. Try thinking about how internal friction affects flow.",
      scaffoldingQuestion: "What happens to the fluid layers sliding past each other?"
    };
  }
};

import React from 'react';
import { Step } from '../types';

interface NavigationProps {
  currentStep: Step;
  onNext: () => void;
  onBack: () => void;
  isNextLocked: boolean;
}

const Navigation: React.FC<NavigationProps> = ({ currentStep, onNext, onBack, isNextLocked }) => {
  return (
    <div className="flex justify-between items-center mt-12 pt-6 border-t border-slate-200 sticky bottom-0 bg-slate-50 pb-6 z-10">
      <button
        onClick={onBack}
        disabled={currentStep === Step.HOOK}
        className="px-6 py-2 rounded-lg font-medium text-slate-600 hover:bg-slate-200 disabled:opacity-30 disabled:cursor-not-allowed transition-all flex items-center gap-2"
      >
        <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="m15 18-6-6 6-6"/></svg>
        Back
      </button>

      <div className="flex gap-2">
        {[0, 1, 2, 3].map((s) => (
          <div
            key={s}
            className={`w-2.5 h-2.5 rounded-full transition-all ${
              s === currentStep ? 'bg-blue-600 scale-125' : 'bg-slate-300'
            }`}
          />
        ))}
      </div>

      <button
        onClick={onNext}
        disabled={isNextLocked || currentStep === Step.COMPLETION}
        className={`px-8 py-2 rounded-lg font-bold text-white transition-all flex items-center gap-2 ${
          isNextLocked 
            ? 'bg-slate-400 cursor-not-allowed opacity-50' 
            : 'bg-blue-600 hover:bg-blue-700 shadow-md hover:shadow-lg active:scale-95'
        }`}
      >
        {isNextLocked ? 'Answer to Unlock' : 'Move Next'}
        <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="m9 18 6-6-6-6"/></svg>
      </button>
    </div>
  );
};

export default Navigation;

import React, { useState, useEffect, useRef } from 'react';

const Simulation: React.FC = () => {
  const [viscosity, setViscosity] = useState(0.5); // 0.1 to 1.0
  const [velocity, setVelocity] = useState(50); // 10 to 100
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    let animationFrameId: number;
    const particles: { x: number; y: number; speed: number }[] = [];

    // Init particles
    for (let i = 0; i < 150; i++) {
      const y = Math.random() * canvas.height;
      // Parabolic velocity profile (No-slip at bottom y=height, max at top y=0)
      // Linear profile for simple shear flow: u(y) = V * (1 - y/H)
      const u_y = velocity * (1 - y / canvas.height);
      particles.push({
        x: Math.random() * canvas.width,
        y,
        speed: u_y
      });
    }

    const draw = () => {
      ctx.clearRect(0, 0, canvas.width, canvas.height);

      // Draw plates
      ctx.fillStyle = '#1e293b';
      ctx.fillRect(0, canvas.height - 10, canvas.width, 10); // Bottom Plate (Stationary)
      ctx.fillStyle = '#3b82f6';
      ctx.fillRect(0, 0, canvas.width, 5); // Top Plate (Moving)

      // Draw velocity profile indicators
      ctx.strokeStyle = 'rgba(59, 130, 246, 0.2)';
      ctx.beginPath();
      for (let y = 0; y < canvas.height; y += 20) {
        const u = velocity * (1 - y / canvas.height);
        ctx.moveTo(50, y);
        ctx.lineTo(50 + u, y);
      }
      ctx.stroke();

      // Draw profile line
      ctx.strokeStyle = '#ef4444';
      ctx.lineWidth = 2;
      ctx.beginPath();
      ctx.moveTo(50 + velocity, 0);
      ctx.lineTo(50, canvas.height);
      ctx.stroke();

      // Update and draw particles
      ctx.fillStyle = '#64748b';
      particles.forEach(p => {
        // Effective speed is reduced by viscosity (higher viscosity = slower response to shear)
        // Here we simulate drag
        const flowSpeed = velocity * (1 - p.y / canvas.height);
        p.speed = flowSpeed / (viscosity * 5 + 1);

        p.x += p.speed * 0.5;
        if (p.x > canvas.width) p.x = 0;

        ctx.beginPath();
        ctx.arc(p.x, p.y, 2, 0, Math.PI * 2);
        ctx.fill();
      });

      animationFrameId = requestAnimationFrame(draw);
    };

    draw();
    return () => cancelAnimationFrame(animationFrameId);
  }, [viscosity, velocity]);

  return (
    <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-inner">
      <div className="mb-4">
        <h3 className="text-lg font-bold text-slate-800">Mini Lab: Shear Flow Visualization</h3>
        <p className="text-sm text-slate-500">Adjust parameters to see how fluid layers (laminae) behave between plates.</p>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-4 gap-6 items-center">
        <div className="md:col-span-3">
          <canvas 
            ref={canvasRef} 
            width={600} 
            height={300} 
            className="w-full h-auto bg-slate-50 rounded-lg border border-slate-100 cursor-crosshair"
          />
        </div>

        <div className="space-y-6">
          <div>
            <label className="block text-sm font-semibold text-slate-700 mb-2">
              Viscosity (&mu;): {viscosity.toFixed(2)}
            </label>
            <input 
              type="range" 
              min="0.1" max="2.0" step="0.05"
              value={viscosity}
              onChange={(e) => setViscosity(parseFloat(e.target.value))}
              className="w-full h-2 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-blue-600"
            />
            <div className="flex justify-between text-[10px] text-slate-400 mt-1">
              <span>Water-like</span>
              <span>Honey-like</span>
            </div>
          </div>

          <div>
            <label className="block text-sm font-semibold text-slate-700 mb-2">
              Plate Velocity (V): {velocity.toFixed(0)}
            </label>
            <input 
              type="range" 
              min="10" max="150" step="5"
              value={velocity}
              onChange={(e) => setVelocity(parseFloat(e.target.value))}
              className="w-full h-2 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-blue-600"
            />
          </div>

          <div className="p-3 bg-blue-50 rounded-lg border border-blue-100 text-xs text-blue-800">
            <strong>Observe:</strong> The red line shows the velocity gradient. Notice how the speed is zero at the bottom wall—this is the <strong>No-Slip Condition</strong>.
          </div>
        </div>
      </div>
    </div>
  );
};

export default Simulation;

import React, { useState } from 'react';
import { analyzeResponse } from '../services/geminiService';
import { AttemptState } from '../types';

interface QuestionBlockProps {
  id: string;
  topic: string;
  question: string;
  onSuccess: () => void;
}

const QuestionBlock: React.FC<QuestionBlockProps> = ({ id, topic, question, onSuccess }) => {
  const [answer, setAnswer] = useState('');
  const [loading, setLoading] = useState(false);
  const [attempts, setAttempts] = useState<AttemptState>({
    count: 0,
    lastFeedback: '',
    isUnlocked: false
  });

  const handleSubmit = async () => {
    if (!answer.trim() || attempts.isUnlocked) return;

    setLoading(true);
    const result = await analyzeResponse(topic, question, answer, attempts.count + 1);

    const newCount = attempts.count + 1;
    const isUnlocked = result.isCorrect || newCount >= 3;

    setAttempts({
      count: newCount,
      lastFeedback: result.message + (result.scaffoldingQuestion ? ` \n\nThinking Prompt: ${result.scaffoldingQuestion}` : ''),
      isUnlocked: isUnlocked
    });

    if (isUnlocked) {
      onSuccess();
    }
    setLoading(false);
  };

  return (
    <div className={`p-6 rounded-xl border-2 transition-all duration-500 ${attempts.isUnlocked ? 'border-green-200 bg-green-50' : 'border-blue-100 bg-white'}`}>
      <h4 className="font-bold text-slate-800 mb-3 flex items-center gap-2">
        <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className="text-blue-500"><path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z"/></svg>
        Talk-Back Question
      </h4>
      <p className="text-slate-700 mb-4 font-medium italic">"{question}"</p>

      <textarea
        value={answer}
        onChange={(e) => setAnswer(e.target.value)}
        disabled={attempts.isUnlocked || loading}
        placeholder="Type your intuition here..."
        className="w-full p-4 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent min-h-[100px] mb-4 bg-slate-50 disabled:opacity-50"
      />

      <div className="flex items-center justify-between">
        <div className="text-xs text-slate-400">
          Attempt {attempts.count}/3
        </div>
        <button
          onClick={handleSubmit}
          disabled={loading || attempts.isUnlocked || !answer.trim()}
          className="px-6 py-2 bg-blue-600 text-white rounded-lg font-bold hover:bg-blue-700 disabled:opacity-50 transition-all flex items-center gap-2"
        >
          {loading ? (
            <svg className="animate-spin h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
              <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
              <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
            </svg>
          ) : 'Submit Prediction'}
        </button>
      </div>

      {attempts.lastFeedback && (
        <div className={`mt-6 p-4 rounded-lg text-sm border whitespace-pre-line animate-in fade-in slide-in-from-top-2 duration-300 ${
          attempts.isUnlocked ? 'bg-green-100 border-green-200 text-green-800' : 'bg-orange-50 border-orange-100 text-orange-800'
        }`}>
          <div className="flex gap-2">
             <span className="font-bold">{attempts.isUnlocked ? 'Concept Mastered:' : 'Concept Coach says:'}</span>
          </div>
          {attempts.lastFeedback}
        </div>
      )}
    </div>
  );
};

export default QuestionBlock;

