import React, { useState } from 'react';
import { Step } from './types';
import Navigation from './components/Navigation';
import Simulation from './components/Simulation';
import QuestionBlock from './components/QuestionBlock';

const App: React.FC = () => {
  const [currentStep, setCurrentStep] = useState<Step>(Step.HOOK);
  const [stepLocks, setStepLocks] = useState({
    [Step.HOOK]: true,
    [Step.EXPLORATION]: false, // Usually unlocked once you see it
    [Step.THEORY]: false,
    [Step.CHALLENGE]: true
  });

  const unlockStep = (step: Step) => {
    setStepLocks(prev => ({ ...prev, [step]: false }));
  };

  const handleNext = () => {
    if (currentStep < Step.COMPLETION) {
      setCurrentStep(currentStep + 1);
    }
  };

  const handleBack = () => {
    if (currentStep > Step.HOOK) {
      setCurrentStep(currentStep - 1);
    }
  };

  return (
    <div className="max-w-4xl mx-auto px-6 py-12 min-h-screen flex flex-col">
      {/* Header */}
      <header className="mb-12">
        <div className="flex items-center gap-3 text-blue-600 mb-2">
          <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M4 19.5v-15A2.5 2.5 0 0 1 6.5 2H20v20H6.5a2.5 2.5 0 0 1-2.5-2.5Z"/><path d="M8 7h6"/><path d="M8 11h8"/></svg>
          <span className="font-bold tracking-widest uppercase text-xs">Unit 2: Fluid Properties</span>
        </div>
        <h1 className="text-4xl font-extrabold text-slate-900 leading-tight">
          Viscosity & The Internal Friction of Fluids
        </h1>
        <p className="text-slate-500 mt-2">A "Talk-Back" interactive chapter using Socratic AI.</p>
      </header>

      {/* Main Content Area */}
      <main className="flex-grow space-y-8 animate-in fade-in duration-700">

        {/* Step 1: HOOK */}
        {currentStep === Step.HOOK && (
          <section className="space-y-6">
            <div className="prose prose-slate max-w-none">
              <h2 className="text-2xl font-bold flex items-center gap-2">
                <span className="bg-blue-100 text-blue-600 w-8 h-8 rounded-full flex items-center justify-center text-sm">1</span>
                Opening Provocation
              </h2>
              <div className="bg-white p-8 rounded-2xl border border-slate-200 shadow-sm relative overflow-hidden">
                <div className="absolute top-0 right-0 w-32 h-32 bg-blue-50 rounded-bl-full opacity-50 -z-0"></div>
                <p className="text-lg leading-relaxed text-slate-800 relative z-10">
                  Imagine you have two identical jars. One is filled with water, the other with cold maple syrup. 
                  You drop a heavy steel marble into both simultaneously. 
                  <br /><br />
                  <strong className="text-blue-700">Predict:</strong> If you could zoom in to the atomic level where the syrup touches the marble, what do you think is actually happening to "slow" the marble down compared to the water? Is it "sticking" to it, or is something else at play?
                </p>
              </div>
            </div>

            <QuestionBlock 
              id="hook-q"
              topic="Introduction to Viscosity"
              question="What is the physical mechanism occurring at the interface of the marble and the fluid that creates resistance?"
              onSuccess={() => unlockStep(Step.HOOK)}
            />
          </section>
        )}

        {/* Step 2: EXPLORATION */}
        {currentStep === Step.EXPLORATION && (
          <section className="space-y-6">
            <div className="prose prose-slate max-w-none">
              <h2 className="text-2xl font-bold flex items-center gap-2">
                <span className="bg-blue-100 text-blue-600 w-8 h-8 rounded-full flex items-center justify-center text-sm">2</span>
                Interactive Exploration
              </h2>
              <p className="text-slate-600 mb-6">
                Physics is best understood through observation. In the simulation below, we have a "Shear Flow." 
                A top plate is moving, and a bottom plate is stationary. 
                Use the sliders to experiment with how the fluid layers respond.
              </p>
            </div>

            <Simulation />

            <div className="p-6 bg-slate-900 text-slate-100 rounded-xl mt-6 shadow-xl">
               <h4 className="font-bold text-blue-400 mb-2 flex items-center gap-2">
                 <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><circle cx="12" cy="12" r="10"/><path d="M12 16v-4"/><path d="M12 8h.01"/></svg>
                 Reflection Prompt
               </h4>
               <p className="italic text-slate-300">
                 "You observed the particles stopped near the wall. What does this suggest about the fluid's speed at the boundary layer? Why is this important?"
               </p>
               <div className="mt-4 text-xs text-slate-500 uppercase tracking-widest font-bold">
                 Think about: No-Slip Condition, Shear Stress, Momentum Transfer
               </div>
            </div>
          </section>
        )}

        {/* Step 3: FORMAL THEORY */}
        {currentStep === Step.THEORY && (
          <section className="space-y-8 animate-in slide-in-from-right-4 duration-500">
            <div className="prose prose-slate max-w-none">
              <h2 className="text-2xl font-bold flex items-center gap-2">
                <span className="bg-blue-100 text-blue-600 w-8 h-8 rounded-full flex items-center justify-center text-sm">3</span>
                The Formal Theory
              </h2>

              <div className="space-y-6">
                <p className="text-slate-800 leading-relaxed">
                  Now that you've felt the "drag" in the simulation, let's define it. 
                  <strong>Viscosity</strong> ($\mu$) is a measure of a fluid's resistance to gradual deformation by shear stress or tensile stress. 
                  Informally, it is "fluid friction."
                </p>

                <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm font-serif italic text-center">
                  Newton's Law of Viscosity:
                  <div className="text-2xl not-italic font-bold my-4 font-sans text-blue-800">
                    {/* Fixed LaTeX curly braces: Wrapped in string literal to prevent JSX from interpreting {du} as JS */}
                    {"$\\tau = \\mu \\frac{du}{dy}$"}
                  </div>
                  <div className="text-sm text-slate-500 not-italic font-sans">
                    {/* Fixed LaTeX curly braces: Wrapped in string literal to prevent JSX from interpreting {du} as JS */}
                    {"Where $\\tau$ is shear stress, $\\mu$ is dynamic viscosity, and $\\frac{du}{dy}$ is the velocity gradient."}
                  </div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  <div className="p-4 bg-white rounded-lg border border-slate-100">
                    <h5 className="font-bold text-slate-800 mb-1">Dynamic Viscosity ($\mu$)</h5>
                    <p className="text-sm text-slate-600">The "absolute" resistance of the fluid. Units: Pa·s or Poise.</p>
                  </div>
                  <div className="p-4 bg-white rounded-lg border border-slate-100">
                    <h5 className="font-bold text-slate-800 mb-1">Kinematic Viscosity ($\nu$)</h5>
                    <p className="text-sm text-slate-600">The ratio of absolute viscosity to density ($\nu = \mu / \rho$). Units: $m^2/s$ or Stokes.</p>
                  </div>
                </div>

                <div className="bg-blue-50 p-6 rounded-xl border-l-4 border-blue-500">
                   <h5 className="font-bold text-blue-800 mb-2 italic">The "Thinking" Book says:</h5>
                   <p className="text-sm text-blue-700 leading-relaxed">
                     Imagine fluid as layers of playing cards. As you move the top card, friction between the cards makes the cards below move too—but a little slower. 
                     Viscosity is the "glue" between those cards. In gases, this "glue" is actually molecules jumping between layers, carrying their momentum with them!
                   </p>
                </div>
              </div>
            </div>
          </section>
        )}

        {/* Step 4: MINI CHALLENGE */}
        {currentStep === Step.CHALLENGE && (
          <section className="space-y-6">
            <div className="prose prose-slate max-w-none">
              <h2 className="text-2xl font-bold flex items-center gap-2">
                <span className="bg-blue-100 text-blue-600 w-8 h-8 rounded-full flex items-center justify-center text-sm">4</span>
                Mini-Challenge: Concept Transfer
              </h2>
              <p className="text-slate-600">
                Let's test if you can apply this to a new scenario. Viscosity isn't a static number—it changes with the environment.
              </p>
            </div>

            <QuestionBlock 
