            <p className="text-xl text-slate-500 max-w-md mx-auto">
              You've successfully navigated the internal friction of fluids. Ready for <strong>Surface Tension</strong> next?
            </p>
            <div className="pt-8">
              <button 
                onClick={() => {
                  setCurrentStep(Step.HOOK);
                  setHookPhase(1);
                  setStepLocks({
                    [Step.HOOK]: true,
                    [Step.EXPLORATION]: true,
                    [Step.THEORY]: false,
                    [Step.CHALLENGE]: true
                  });
                }}
                className="px-8 py-3 bg-slate-800 text-white rounded-xl font-bold hover:bg-slate-900 transition-all shadow-lg"
              >
                Restart Chapter
              </button>
            </div>
          </section>
        )}

      </main>

      <Navigation 
        currentStep={currentStep} 
        onNext={handleNext} 
        onBack={handleBack} 
        isNextLocked={stepLocks[currentStep as keyof typeof stepLocks] ?? false}
      />
    </div>
  );
};

