const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const SYSTEM_PROMPT = `You are an expert Fluid Mechanics educator and AI learning architect for a "Talk-Back Book." 
Your role is to act as a Socratic coach, misconception detector, and scaffolding provider.

RULES:
1. NEVER give the final answer directly unless it's the user's 3rd failed attempt.
2. Be conversational but rigorous.
3. Use the "Predict -> Observe -> Explain" model.
4. If a user is wrong, identify the misconception and ask a single, highly-focused scaffolding question to guide them.
5. For "Why?" questions, push for molecular-level reasoning (momentum transfer, intermolecular forces).
6. Your response MUST be in JSON format.`;

export const analyzeResponse = async (
  topic: string,
  question: string,
  userAnswer: string,
  attemptNumber: number
): Promise<{ isCorrect: boolean; message: string; scaffoldingQuestion?: string }> => {
  // Use gemini-3-pro-preview for complex reasoning and scientific analysis tasks
  const model = 'gemini-3-pro-preview';

  const prompt = `
    Topic: ${topic}
    Question: ${question}
    User's Answer: "${userAnswer}"
    Attempt Number: ${attemptNumber}

    Task:
    - Determine if the answer is conceptually correct.
    - If correct, congratulate them and briefly explain why.
    - If incorrect and attempt < 3, provide a hint (scaffolding question) that addresses their likely misconception.
    - If incorrect and attempt == 3, provide the correct explanation and answer.

    Return JSON format:
    {
      "isCorrect": boolean,
      "message": "Feedback for the user",
      "scaffoldingQuestion": "A follow-up hint question (optional if correct or 3rd attempt)"
    }
  `;

  try {
    const response = await ai.models.generateContent({
      model,
      contents: prompt,
      config: {
        systemInstruction: SYSTEM_PROMPT,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            isCorrect: { type: Type.BOOLEAN },
            message: { type: Type.STRING },
            scaffoldingQuestion: { type: Type.STRING }
          },
          required: ["isCorrect", "message"]
        }
      }
    });

    return JSON.parse(response.text || '{}');
  } catch (error) {
    console.error("Gemini API Error:", error);
    return {
      isCorrect: false,
      message: "I'm having trouble processing that right now. Try thinking about how internal friction affects flow.",
      scaffoldingQuestion: "What happens to the fluid layers sliding past each other?"
    };
  }
};

