import { GoogleGenAI, Type } from "@google/genai";
import { ScaffoldingResult, MisconceptionType, StudentLevel } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const SCAFFOLDING_SYSTEM_PROMPT = `
You are an AI Scaffolding Agent inside a Talk-Back Book for Fluid Mechanics.
Your goal is to reduce cognitive load step-by-step until the student self-corrects.

RULES:
1. NEVER give direct answers immediately.
2. Guide the student using simpler questions, analogies, and physical reasoning.
3. One idea at a time.
4. No formulas unless explicitly allowed.
5. No "exam language" (e.g., "calculate", "derive"). Use a patient, encouraging tone.
6. Do NOT mention the word "viscosity" in the first scaffold attempt.

ATTEMPT STRATEGY:
- Attempt 1: Light Hint-based question targeting the misconception.
- Attempt 2: Medium Guided analogy.
- Attempt 3: Reveal Mode - Provide a clear intuition (like sliding cards) and the final explanation.
`;

/** 
 * Rule Layer: Deterministic classification of common student errors 
 */
const classifyMisconception = (answer: string): MisconceptionType => {
  const lowAnswer = answer.toLowerCase();
  if (/\b(heavy|weight|mass|dense|density|gravity)\b/i.test(lowAnswer)) return 'density';
  if (/\b(surface|container|wall|glass|edge|outside)\b/i.test(lowAnswer)) return 'external_friction';
  if (/\b(thick|sticky|gooey|slow)\b/i.test(lowAnswer) && lowAnswer.length < 30) return 'vague';
  return 'unknown';
};

export const analyzeResponse = async (
  concept: string,
  question: string,
  userAnswer: string,
  attemptCount: number,
  studentLevel: StudentLevel = 'average'
): Promise<ScaffoldingResult> => {
  const misconception = classifyMisconception(userAnswer);
  const modelName = 'gemini-3-pro-preview';

  const prompt = `
    Concept: ${concept}
    Original Question: "${question}"
    Student Answer: "${userAnswer}"

    Detected Misconception: ${misconception}
    Attempt Number: ${attemptCount}
    Student Level: ${studentLevel}

    Task:
    1. Determine if the answer is conceptually correct.
    2. If incorrect, generate a scaffolding question based on the attempt number.
    3. If attempt is 3, trigger "Reveal Mode" with the "Card Stack" analogy.

    Return JSON:
    {
      "isCorrect": boolean,
      "message": "Feedback string (if correct, praise; if incorrect, short observation)",
      "scaffoldingQuestion": "The single guiding question for the student (null if correct)",
      "internalReasoning": "Short explanation of why this scaffold helps"
    }
  `;

  try {
    const response = await ai.models.generateContent({
      model: modelName,
      contents: prompt,
      config: {
        systemInstruction: SCAFFOLDING_SYSTEM_PROMPT,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            isCorrect: { type: Type.BOOLEAN },
            message: { type: Type.STRING },
            scaffoldingQuestion: { type: Type.STRING },
            internalReasoning: { type: Type.STRING }
          },
          required: ["isCorrect", "message"]
        }
      }
    });

    const result = JSON.parse(response.text || '{}');
    return { ...result, misconceptionFound: misconception };
  } catch (error) {
    console.error("Scaffolding Error:", error);
    return {
      isCorrect: false,
      message: "I see you're thinking about the fluid's resistance.",
      scaffoldingQuestion: "Does the resistance come from the container walls or from inside the fluid itself?",
      misconceptionFound: 'unknown'
    };
  }
};

