  };

  const toggleSubchapter = (id: string) => {
    setExpandedSubchapters(prev => ({ ...prev, [id]: !prev[id] }));
  };

  // Logic to determine if a lesson should be unlocked based on linear progression
  const isUnlocked = (path: string, index: number, allLessons: MicroLesson[]) => {
    if (index === 0 && path === "01_properties_of_fluids/01_viscosity/01_fundamentals/micro_01") return true;

