    [Step.REAL_WORLD]: "7. Context",
    [Step.REFLECTION]: "8. Reflection",
    [Step.CHALLENGE]: "9. Challenge",
    [Step.COMPLETION]: "10. Done"
  };

  return (
    <div className="fixed bottom-0 left-0 right-0 bg-white/80 backdrop-blur-xl border-t border-slate-200 p-4 z-[50] flex items-center justify-center">
      <div className="max-w-4xl w-full flex items-center justify-between gap-8">

        {/* Previous Arrow */}
        <button
          onClick={onBack}
          disabled={!canGoBack}
          className={`flex items-center gap-3 px-6 py-4 rounded-2xl font-black text-xs uppercase tracking-[0.2em] transition-all
