          <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4" strokeLinecap="round" strokeLinejoin="round"><path d="m15 18-6-6 6-6"/></svg>
          Prev
        </button>

        {/* Progress Map */}
        <div className="hidden md:flex items-center gap-1.5 overflow-x-auto py-2">
          {Object.entries(stepLabels).map(([stepIdx, label]) => {
            const idx = parseInt(stepIdx);
            const isActive = idx === currentStep;
            const isPast = idx < currentStep;

            return (
              <div key={idx} className="flex items-center group">
                <div className={`
                  text-[8px] font-black uppercase tracking-tighter px-2 py-1 rounded-md transition-all
                  ${isActive ? 'bg-blue-600 text-white scale-110 shadow-lg' : 'text-slate-400 group-hover:text-slate-600'}
                  ${isPast ? 'text-blue-400' : ''}
                `}>
                  {label.split('. ')[1]}
                </div>
                {idx < Step.COMPLETION && <div className={`w-2 h-[2px] rounded-full mx-1 ${isPast ? 'bg-blue-200' : 'bg-slate-100'}`} />}
