            );
          })}
        </div>

        {/* Next Arrow */}
        <button
          onClick={onNext}
          disabled={!canGoNext}
          className={`flex items-center gap-3 px-8 py-4 rounded-2xl font-black text-xs uppercase tracking-[0.2em] transition-all
