  if (!lessonData) return <div>Loading...</div>;

  return (
    <div className="max-w-4xl mx-auto px-6 py-12 min-h-screen flex flex-col bg-slate-50 relative pb-40">
      <div className="fixed top-8 left-8 z-50">
