        >
          <div className="absolute inset-0 bg-blue-600 translate-y-full group-hover:translate-y-0 transition-transform duration-300"></div>
          <span className="relative z-10 font-black text-xs uppercase tracking-[0.2em]">Chapter Directory</span>
        </button>
      </div>

      <Sidebar isOpen={isSidebarOpen} onClose={() => setIsSidebarOpen(false)} onNavigate={handleNavigate} activePath={activeLessonPath} completedPaths={[]} />

      <header className="mb-12 border-b border-slate-200 pb-8 pt-16">
        <div className="flex items-center gap-3 text-blue-600 mb-4">
          <span className="font-black tracking-[0.25em] uppercase text-[10px] text-slate-400">
            {allMicroLessons[currentLessonIndex]?.title || "Micro-Lesson"}
          </span>
        </div>

        {/* Only show 'Introduction to Viscosity' on the first slide of Lesson 1 */}
        <h1 className="text-6xl font-black text-slate-900 leading-none tracking-tighter mb-4">
          {isLesson01 && currentStep === Step.HOOK ? "Introduction to Viscosity" : (lessonData.theory?.title || "Newton's Law of Viscosity")}
