        {/* Learning Outcomes for Lesson 1, Step 1 */}
        {isLesson01 && currentStep === Step.HOOK && lessonData.metadata.outcomes && (
          <div className="mt-8 p-6 bg-white border border-slate-200 rounded-[32px] shadow-sm animate-in fade-in slide-in-from-top-4 duration-500">
             <h4 className="text-[10px] font-black uppercase tracking-[0.3em] text-blue-600 mb-3">Learning Outcomes</h4>
             <ul className="space-y-2">
                {lessonData.metadata.outcomes.map((o: string, i: number) => (
                  <li key={i} className="flex gap-3 text-sm font-bold text-slate-600 leading-tight">
                    <div className="w-1.5 h-1.5 rounded-full bg-blue-400 mt-1.5 shrink-0" />
                    {o}
                  </li>
                ))}
             </ul>
          </div>
        )}
      </header>

      <main className="flex-grow space-y-16">
        {currentStep === Step.HOOK && (
