               <p className="text-slate-400 font-bold uppercase tracking-widest text-xs">Stage 1: The Hook</p>
            </div>
          </section>
        )}

        {currentStep === Step.PREP_COMMITMENT && (
          <section className="space-y-10 animate-in fade-in duration-500">
            <QuestionBlock id="prep" topic="Initial Prediction" question={lessonData.hook.commitment_question} onSuccess={handleNext} />
          </section>
        )}

        {currentStep === Step.INTERACTION && (
          <section className="space-y-10 animate-in slide-in-from-right-10 duration-700">
            <div className="prose prose-slate max-w-none">
              <h2 className="text-3xl font-black text-slate-800 uppercase tracking-tighter">Interaction</h2>
              <p className="text-xl text-slate-600 font-medium leading-relaxed">{lessonData.interaction.instruction}</p>
            </div>
