        {currentStep === Step.THEORY && (
          <section className="space-y-10 animate-in zoom-in-95 duration-500">
             <div className="bg-white p-12 rounded-[56px] border border-slate-200 shadow-2xl relative">
                <div className="absolute top-8 right-12 text-[10px] font-black text-slate-300 uppercase tracking-widest">Synthesis</div>
                <h2 className="text-4xl font-black mb-6">{lessonData.theory.title}</h2>
                <p className="text-2xl text-slate-700 leading-relaxed mb-8">{lessonData.theory.content}</p>
                {lessonData.theory.formula && (
                  <div className="bg-slate-900 p-12 rounded-[40px] flex items-center justify-center text-5xl font-black text-blue-400 mb-8 tracking-tighter">
                    {`$${lessonData.theory.formula}$`}
                  </div>
                )}
                <div className="bg-slate-50 p-8 rounded-3xl border border-slate-100">
                   <h4 className="text-[10px] font-black uppercase text-blue-600 tracking-widest mb-3">The Intuition</h4>
                   <p className="text-xl font-bold italic text-slate-700 leading-snug">"{lessonData.theory.analogy}"</p>
                </div>
             </div>
          </section>
        )}

        {currentStep === Step.TRANSFER && (
          <section className="space-y-10 animate-in fade-in duration-500">
            <QuestionBlock id="transfer" topic="Concept Transfer" question={lessonData.transfer.prompt} onSuccess={handleNext} />
          </section>
        )}

        {currentStep === Step.REAL_WORLD && (
          <section className="space-y-10 animate-in slide-in-from-bottom-8 duration-500">
            <div className="bg-amber-600 text-white p-12 rounded-[56px] shadow-2xl">
               <h4 className="font-black uppercase tracking-[0.4em] text-[10px] mb-6 text-amber-200">Engineering Insight</h4>
               <p className="text-3xl font-black leading-tight italic">"{lessonData.transfer.real_world}"</p>
            </div>
          </section>
        )}

        {currentStep === Step.CHALLENGE && (
          <section className="space-y-10 animate-in slide-in-from-right-10 duration-700">
            <h2 className="text-3xl font-black">Level Challenge</h2>
            {lessonData.challenges.map((c: any, i: number) => (
              <QuestionBlock key={i} id={`challenge_${i}`} topic={c.level} question={c.question} onSuccess={handleNext} />
            ))}
          </section>
        )}

        {currentStep === Step.COMPLETION && (
          <section className="text-center py-24 space-y-10 animate-in slide-in-from-bottom-20 duration-1000">
            <div className="w-40 h-40 bg-green-100 text-green-600 rounded-[48px] mx-auto flex items-center justify-center shadow-2xl">
               <svg xmlns="http://www.w3.org/2000/svg" width="72" height="72" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><polyline points="20 6 9 17 4 12"/></svg>
            </div>
            <h2 className="text-7xl font-black tracking-tighter">Micro-Lesson Mastered</h2>
            <p className="text-2xl text-slate-500 font-bold max-w-lg mx-auto">You've unlocked the next layer of the book. Ready to move on?</p>
          </section>
        )}
      </main>

      <Navigation 
        currentStep={currentStep} 
        onNext={handleNext} 
        onBack={handleBack} 
        isNextLocked={false} 
      />
    </div>
  );
};

