import React, { useState, useMemo } from 'react';
import { Step, LessonContent } from './types';
import Navigation from './components/Navigation';
import Simulation from './components/Simulation';
import QuestionBlock from './components/QuestionBlock';
import HookImage from './components/HookImage';
import Sidebar from './components/Sidebar';
import { CURRICULUM } from './curriculum';
import { MICRO_CONTENT as MICRO_01 } from './01_properties_of_fluids/01_viscosity/01_fundamentals/micro_01_physical_meaning_honey_vs_water/content';
import { MICRO_02_DATA as MICRO_02 } from './01_properties_of_fluids/01_viscosity/01_fundamentals/micro_02_newtons_law_of_viscosity/metadata';

const App: React.FC = () => {
  const [currentStep, setCurrentStep] = useState<Step>(Step.HOOK);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [activeLessonPath, setActiveLessonPath] = useState("01_properties_of_fluids/01_viscosity/01_fundamentals/micro_01_physical_meaning_honey_vs_water");
  const [socraticIndex, setSocraticIndex] = useState(0);

  const allMicroLessons = useMemo(() => {
    return CURRICULUM.chapters.flatMap(c => 
      c.subchapters.flatMap(s => 
        s.topics.flatMap(t => t.microLessons)
      )
    );
  }, []);

  const currentLessonIndex = allMicroLessons.findIndex(m => m.path === activeLessonPath);
  const isLesson01 = activeLessonPath.includes('micro_01');

  // Explicitly typing lessonData to LessonContent | null to resolve property access errors
  const lessonData: LessonContent | null = useMemo(() => {
    if (activeLessonPath.includes('micro_01')) return MICRO_01 as LessonContent;
    if (activeLessonPath.includes('micro_02')) return MICRO_02 as LessonContent;
    return null;
  }, [activeLessonPath]);

  const handleNext = () => {
    if (currentStep < Step.COMPLETION) {
      setCurrentStep(currentStep + 1);
    } else if (currentLessonIndex < allMicroLessons.length - 1) {
      const nextLesson = allMicroLessons[currentLessonIndex + 1];
      setActiveLessonPath(nextLesson.path);
      setCurrentStep(Step.HOOK);
      setSocraticIndex(0);
    }
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleBack = () => {
    if (currentStep > Step.HOOK) {
      setCurrentStep(currentStep - 1);
    } else if (currentLessonIndex > 0) {
      const prevLesson = allMicroLessons[currentLessonIndex - 1];
      setActiveLessonPath(prevLesson.path);
      setCurrentStep(Step.COMPLETION);
      setSocraticIndex(0);
    }
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleNavigate = (path: string) => {
    setActiveLessonPath(path);
    setCurrentStep(Step.HOOK);
    setSocraticIndex(0);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

